from dataclasses import dataclass
from typing import Union, Optional


@dataclass
class ASTNode:
    """Abstract Syntax Tree node for mathematical expressions"""
    type: str  # 'number', 'binop', or 'unary'
    value: Optional[float] = None  # for numbers
    op: Optional[str] = None  # for operators
    left: Optional['ASTNode'] = None  # for binary operations
    right: Optional['ASTNode'] = None  # for binary operations
    operand: Optional['ASTNode'] = None  # for unary operations


class ExpressionParser:
    """Mathematical expression parser that creates and evaluates ASTs"""

    def __init__(self):
        self.tokens = []
        self.current_token_index = 0

    def parse(self, expression: str) -> ASTNode:
        """Parse a string expression into an AST"""
        # Tokenize the expression
        self.tokens = self._tokenize(expression)
        self.current_token_index = 0

        if not self.tokens:
            raise ValueError("Empty expression")

        # Parse the expression
        ast = self._parse_expression()

        # Check if we've consumed all tokens
        if self.current_token_index < len(self.tokens):
            raise ValueError(f"Unexpected token: {self.tokens[self.current_token_index]}")

        return ast

    def _tokenize(self, expression: str) -> list:
        """Convert string expression into tokens"""
        tokens = []
        i = 0
        n = len(expression)

        while i < n:
            c = expression[i]

            if c.isspace():
                i += 1
                continue

            if c in '0123456789.':
                # Parse number
                num_str = []
                while i < n and (expression[i].isdigit() or expression[i] == '.'):
                    num_str.append(expression[i])
                    i += 1
                try:
                    num = float(''.join(num_str))
                    tokens.append(('NUMBER', num))
                except ValueError:
                    raise ValueError(f"Invalid number format: {''.join(num_str)}")
                continue

            if c in '+-*/()':
                tokens.append(('OPERATOR', c))
                i += 1
                continue

            raise ValueError(f"Invalid character: {c}")

        return tokens

    def _current_token(self):
        """Get current token or None if at end"""
        if self.current_token_index < len(self.tokens):
            return self.tokens[self.current_token_index]
        return None

    def _eat(self, token_type=None):
        """Consume current token, optionally checking type"""
        token = self._current_token()
        if token is None:
            raise ValueError("Unexpected end of expression")

        if token_type is not None and token[0] != token_type:
            raise ValueError(f"Expected {token_type}, got {token[0]}")

        self.current_token_index += 1
        return token

    def _parse_expression(self):
        """Parse expression with operator precedence"""
        return self._parse_additive()

    def _parse_additive(self):
        """Parse addition and subtraction (lowest precedence)"""
        node = self._parse_multiplicative()

        while self._current_token() and self._current_token()[1] in ('+', '-'):
            op = self._eat('OPERATOR')[1]
            right = self._parse_multiplicative()
            node = ASTNode(type='binop', op=op, left=node, right=right)

        return node

    def _parse_multiplicative(self):
        """Parse multiplication and division (higher precedence)"""
        node = self._parse_unary()

        while self._current_token() and self._current_token()[1] in ('*', '/'):
            op = self._eat('OPERATOR')[1]
            right = self._parse_unary()
            node = ASTNode(type='binop', op=op, left=node, right=right)

        return node

    def _parse_unary(self):
        """Parse unary minus (highest precedence)"""
        if self._current_token() and self._current_token()[1] == '-':
            self._eat('OPERATOR')
            operand = self._parse_unary()  # Allow nested unary
            return ASTNode(type='unary', op='-', operand=operand)

        return self._parse_primary()

    def _parse_primary(self):
        """Parse primary expressions (numbers and parentheses)"""
        token = self._current_token()
        if token is None:
            raise ValueError("Unexpected end of expression")

        if token[0] == 'NUMBER':
            value = self._eat('NUMBER')[1]
            return ASTNode(type='number', value=value)

        if token[1] == '(':
            self._eat('OPERATOR')  # Eat '('
            node = self._parse_expression()
            if self._current_token() and self._current_token()[1] == ')':
                self._eat('OPERATOR')  # Eat ')'
                return node
            else:
                raise ValueError("Unmatched parenthesis")

        raise ValueError(f"Unexpected token: {token[1]}")


def parse(expression: str) -> ASTNode:
    """Parse a string expression into an AST"""
    parser = ExpressionParser()
    return parser.parse(expression)


def evaluate(node: ASTNode) -> float:
    """Evaluate an AST to a numeric result"""
    if node.type == 'number':
        return node.value

    elif node.type == 'binop':
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)

        if node.op == '+':
            return left_val + right_val
        elif node.op == '-':
            return left_val - right_val
        elif node.op == '*':
            return left_val * right_val
        elif node.op == '/':
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val

    elif node.type == 'unary':
        operand_val = evaluate(node.operand)
        if node.op == '-':
            return -operand_val

    raise ValueError(f"Invalid AST node type: {node.type}")


# Test cases
if __name__ == "__main__":
    test_cases = [
        "5",
        "3 + 4",
        "10 - 2 * 3",
        "(3 + 4) * 2",
        "-5",
        "-(3 + 2)",
        "10 / 2",
        "3 + 4 * 2 - 1",
        "((2 + 3) * (4 - 1)) / 3",
    ]

    for expr in test_cases:
        try:
            ast = parse(expr)
            result = evaluate(ast)
            print(f"'{expr}' = {result}")
        except Exception as e:
            print(f"'{expr}' Error: {e}")
